/*
 * RSA Public Key Cryptosystem Implementation
 * Based on the educational example: p=3, q=11
 * Public Key: (e=7, n=33)
 * Private Key: (d=3, n=33)
 */

#include <stdio.h>

// Function prototypes
long mod_exp(long base, long exp, long mod);
long mod_inverse(long a, long m);
void generate_keys(long p, long q, long *e, long *d, long *n);
long encrypt_char(char plaintext, long e, long n);
char decrypt_char(long ciphertext, long d, long n);

/* Extended Euclidean Algorithm */
long extended_gcd(long a, long b, long *x, long *y) {
    if (a == 0) {
        *x = 0;
        *y = 1;
        return b;
    }
    long x1, y1;
    long gcd = extended_gcd(b % a, a, &x1, &y1);
    *x = y1 - (b / a) * x1;
    *y = x1;
    return gcd;
}

/* Modular exponentiation: base^exp mod mod */
long mod_exp(long base, long exp, long mod) {
    long result = 1;
    base = base % mod;

    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        exp = exp / 2;
        base = (base * base) % mod;
    }
    return result;
}

/* Modular inverse using Extended Euclidean Algorithm */
long mod_inverse(long a, long m) {
    long x, y;
    long gcd = extended_gcd(a, m, &x, &y);

    if (gcd != 1) {
        return -1;  // No inverse exists
    }
    return (x % m + m) % m;
}

/* Generate RSA key pair */
void generate_keys(long p, long q, long *e, long *d, long *n) {
    *n = p * q;
    long phi_n = (p - 1) * (q - 1);

    // Public exponent e (must be coprime to phi_n)
    *e = 7;

    // Private exponent d (modular inverse of e mod phi_n)
    *d = mod_inverse(*e, phi_n);

    printf("    n = p × q = %ld × %ld = %ld\n", p, q, *n);
    printf("    φ(n) = (p-1)(q-1) = %ld × %ld = %ld\n", 
           p-1, q-1, phi_n);
}

/* Encrypt a character using public key */
long encrypt_char(char plaintext, long e, long n) {
    long p = (long)plaintext;  // Convert char to ASCII value
    return mod_exp(p, e, n);
}

/* Decrypt using private key */
char decrypt_char(long ciphertext, long d, long n) {
    long p = mod_exp(ciphertext, d, n);
    return (char)p;
}

int main() {
    long p = 3, q = 11;
    long e, d, n;

    printf("========================================================\n");
    printf("   RSA Public Key Cryptosystem - C Implementation\n");
    printf("========================================================\n\n");

    // Key Generation
    printf("1. KEY GENERATION\n");
    printf("   Input primes: p = %ld, q = %ld\n", p, q);
    generate_keys(p, q, &e, &d, &n);

    printf("\n   Generated Keys:\n");
    printf("   Public Key (e, n): (%ld, %ld)\n", e, n);
    printf("   Private Key (d, n): (%ld, %ld)\n", d, n);
    printf("   Verification: (d × e) mod φ(n) = (%ld × %ld) mod %ld = %ld\n",
           d, e, (p-1)*(q-1), (d * e) % ((p-1)*(q-1)));

    // Encryption Example (from content: P=4)
    long P = 4;
    long C = mod_exp(P, e, n);

    printf("\n2. ENCRYPTION (Alice -> Bob)\n");
    printf("   Message P = %ld\n", P);
    printf("   C = P^e mod n = %ld^%ld mod %ld\n", P, e, n);
    printf("   Ciphertext C = %ld\n", C);

    // Decryption Example
    long decrypted_P = mod_exp(C, d, n);

    printf("\n3. DECRYPTION (Bob receives C=%ld)\n", C);
    printf("   P = C^d mod n = %ld^%ld mod %ld\n", C, d, n);
    printf("   Decrypted message P = %ld\n", decrypted_P);

    printf("\n4. RESULT: %ld == %ld ? %s\n\n", 
           P, decrypted_P, (P == decrypted_P) ? "YES - Success!" : "NO - Error!");

    // Character encryption demo
    printf("========================================================\n");
    printf("   Bonus: Character Message Encryption\n");
    printf("========================================================\n\n");

    char message = 'X';
    long encrypted = encrypt_char(message, e, n);
    char decrypted = decrypt_char(encrypted, d, n);

    printf("   Original char: '%c' (ASCII: %d)\n", message, (int)message);
    printf("   Encrypted:     %ld\n", encrypted);
    printf("   Decrypted:     '%c'\n", decrypted);

    printf("\n   Time Complexity: O(log n) - modular exponentiation\n");
    printf("   Space Complexity: O(1)\n");

    return 0;
}
